syntax = "proto3";

package jsonldtest;


option java_multiple_files = true;
option java_package = "demo.orders.v1";
option java_outer_classname = "OrderServiceProto";

service OrderService {
  // 1) Unary
  rpc GetOrder(GetOrderRequest) returns (Order);
  rpc GetOrders(OrderStatus) returns (OrdersList);


  // 2) Server streaming
  rpc WatchOrderStatus(WatchOrderStatusRequest) returns (stream StatusUpdate);

  // 3) Client streaming
  rpc AddLineItems(stream LineItem) returns (AddLineItemsResult);

  // 4) Bidirectional streaming
  rpc CartSession(stream CartAction) returns (stream CartEvent);
}

// -----------------------
// Unary: GetOrder
// -----------------------
message GetOrderRequest {
  string order_id = 1;
}
message OrdersList {
  repeated Order order = 1;
}
message Order {
  string order_id = 1;
  OrderStatus status = 2;
  Money total = 3;
  repeated OrderLine lines = 4;
  int64 created_at_epoch_ms = 5;
}

message OrderLine {
  string sku = 1;
  string name = 2;
  int32 quantity = 3;
  Money unit_price = 4;
  Money line_total = 5;
}

// -----------------------
// Server streaming: WatchOrderStatus
// -----------------------
message WatchOrderStatusRequest {
  string order_id = 1;
  bool include_current = 2;
  int32 max_updates = 3;
}

message StatusUpdate {
  string order_id = 1;
  OrderStatus status = 2;
  string message = 3;
  int64 event_time_epoch_ms = 4;
}

// -----------------------
// Client streaming: AddLineItems
// -----------------------
message LineItem {
  string order_id = 1;
  string sku = 2;
  string name = 3;
  int32 quantity = 4;
  Money unit_price = 5;
}

message AddLineItemsResult {
  string order_id = 1;
  int32 accepted = 2;
  int32 rejected = 3;
  repeated ItemRejection rejections = 4;
  Money new_total = 5;
}

message ItemRejection {
  string sku = 1;
  string reason = 2;
}

// -----------------------
// Bidirectional streaming: CartSession
// -----------------------
message CartAction {
  string session_id = 1;
  int64 client_time_epoch_ms = 2;

  oneof action {
    AddItem add_item = 10;
    RemoveItem remove_item = 11;
    UpdateQuantity update_quantity = 12;
    ApplyCoupon apply_coupon = 13;
    SetAddress set_address = 14;
    Ping ping = 15;
    Checkout checkout = 16;
  }
}

message CartEvent {
  string session_id = 1;
  int64 server_time_epoch_ms = 2;

  oneof event {
    PriceUpdated price_updated = 10;
    CouponAccepted coupon_accepted = 11;
    CouponRejected coupon_rejected = 12;
    OutOfStock out_of_stock = 13;
    ShippingUpdated shipping_updated = 14;
    ValidationError validation_error = 15;
    Pong pong = 16;
    CheckoutSuccess checkout_success = 17;
  }
}

message AddItem {
  string sku = 1;
  string name = 2;
  int32 quantity = 3;
  Money unit_price = 4;
}

message RemoveItem {
  string sku = 1;
}

message UpdateQuantity {
  string sku = 1;
  int32 quantity = 2;
}

message ApplyCoupon {
  string code = 1;
}

message SetAddress {
  Address address = 1;
}

message Ping {
  string nonce = 1;
}

message PriceUpdated {
  Money subtotal = 1;
  Money discount = 2;
  Money shipping = 3;
  Money tax = 4;
  Money total = 5;
}

message CouponAccepted {
  string code = 1;
  Money discount = 2;
}

message CouponRejected {
  string code = 1;
  string reason = 2;
}

message OutOfStock {
  string sku = 1;
  string message = 2;
}

message ShippingUpdated {
  string carrier = 1;
  string service_level = 2;
  Money shipping = 3;
  int32 estimated_days = 4;
}

message ValidationError {
  string field = 1;
  string message = 2;
}

message Pong {
  string nonce = 1;
}

message Checkout {
  PaymentMethod payment_method = 1;
  string payment_token = 2;
}

message CheckoutSuccess {
  string order_id = 1;
  repeated CartLineItem line_items = 2;
  Money subtotal = 3;
  Money discount = 4;
  Money shipping = 5;
  Money tax = 6;
  Money total = 7;
  string payment_method = 8;
  Address shipping_address = 9;
  int64 order_time_epoch_ms = 10;
  string confirmation_message = 11;
}

message CartLineItem {
  string sku = 1;
  string name = 2;
  int32 quantity = 3;
  Money unit_price = 4;
  Money line_total = 5;
}

enum PaymentMethod {
  PAYMENT_METHOD_UNSPECIFIED = 0;
  CREDIT_CARD = 1;
  DEBIT_CARD = 2;
  UPI = 3;
  NET_BANKING = 4;
  CASH_ON_DELIVERY = 5;
}

// -----------------------
// Common types
// -----------------------
enum OrderStatus {
  ORDER_STATUS_UNSPECIFIED = 0;
  ORDER_STATUS_CREATED = 1;
  ORDER_STATUS_CONFIRMED = 2;
  ORDER_STATUS_PACKED = 3;
  ORDER_STATUS_SHIPPED = 4;
  ORDER_STATUS_OUT_FOR_DELIVERY = 5;
  ORDER_STATUS_DELIVERED = 6;
  ORDER_STATUS_CANCELLED = 7;
}

message Money {
  string currency_code = 1;
  int64 units_minor = 2;
}

message Address {
  string name = 1;
  string line1 = 2;
  string line2 = 3;
  string city = 4;
  string state = 5;
  string postal_code = 6;
  string country_code = 7;
}
